+
+export function fetchSourcePullRequestHead({
+  targetDir,
+  sourcePr,
+}: {
+  targetDir: string;
+  sourcePr: GitHubRef;
+}): string {
+  const sourceRef = sourcePullRequestRemoteRef(sourcePr.number);
+  run("git", ["fetch", "origin", sourcePullRequestFetchSpec(sourcePr.number, sourceRef)], {
+    cwd: targetDir,
+  });
+  return sourceRef;
